// Aggregate weekly metrics for this deal/vendor
const deal = $input.item.json;

const daysOnMarket = Number(deal.days_on_market) || 0;
const visitsCount = Number(deal.visits_last_7d) || 0;
const inquiriesCount = Number(deal.inquiries_last_7d) || 0;
const activitiesTotal = Number(deal.activities_last_7d) || 0;
const avgInterest = Number(deal.avg_interest_level) || 0;

// Market benchmarks (Portugal 2026)
const MEDIAN_DOM_PORTUGAL = 210;
const PRICE_PER_M2_LISBON = 5000;
const PRICE_PER_M2_PORTO = 3643;
const PRICE_PER_M2_ALGARVE = 3941;
const PRICE_PER_M2_MARKET_MEDIAN = 3076;

// Price positioning vs market
const pricePerM2 = deal.area_m2 > 0 ? (deal.property_price / deal.area_m2) : 0;
const zone = (deal.zone || '').toLowerCase();
let marketRefPricePerM2;
if (zone.includes('lisboa') || zone.includes('lisbon')) {
  marketRefPricePerM2 = PRICE_PER_M2_LISBON;
} else if (zone.includes('porto')) {
  marketRefPricePerM2 = PRICE_PER_M2_PORTO;
} else if (zone.includes('algarve') || zone.includes('faro')) {
  marketRefPricePerM2 = PRICE_PER_M2_ALGARVE;
} else {
  marketRefPricePerM2 = PRICE_PER_M2_MARKET_MEDIAN;
}

const pricePositionPct = marketRefPricePerM2 > 0
  ? Math.round(((pricePerM2 - marketRefPricePerM2) / marketRefPricePerM2) * 100)
  : 0;

let pricePositionLabel;
if (pricePositionPct > 15) pricePositionLabel = 'acima do mercado';
else if (pricePositionPct > 5) pricePositionLabel = 'ligeiramente acima';
else if (pricePositionPct >= -5) pricePositionLabel = 'alinhado com mercado';
else if (pricePositionPct >= -15) pricePositionLabel = 'competitivo';
else pricePositionLabel = 'abaixo do mercado';

// DOM performance vs median
const domPerformance = MEDIAN_DOM_PORTUGAL - daysOnMarket;
const domLabel = daysOnMarket <= 30 ? 'recente'
  : daysOnMarket <= 90 ? 'em linha com o mercado'
  : daysOnMarket <= 180 ? 'acima da média'
  : 'necessita atenção de preço';

// Activity trend assessment
let activityTrend;
if (visitsCount >= 3 || inquiriesCount >= 5) activityTrend = 'forte';
else if (visitsCount >= 1 || inquiriesCount >= 2) activityTrend = 'moderada';
else activityTrend = 'baixa';

const weekOf = new Date();
const weekStr = weekOf.toLocaleDateString('pt-PT', { day: '2-digit', month: 'long', year: 'numeric' });

return [{
  json: {
    ...deal,
    metrics: {
      visits_count: visitsCount,
      inquiries_received: inquiriesCount,
      activities_total: activitiesTotal,
      avg_interest_level: Math.round(avgInterest * 10) / 10,
      days_on_market: daysOnMarket,
      price_per_m2: Math.round(pricePerM2),
      market_ref_price_per_m2: marketRefPricePerM2,
      price_position_pct: pricePositionPct,
      price_position_label: pricePositionLabel,
      dom_label: domLabel,
      activity_trend: activityTrend,
      dom_vs_median_days: domPerformance
    },
    week_of: weekStr,
    report_date: weekOf.toISOString().split('T')[0]
  }
}];

