// Parse Claude report and build final email HTML
const deal = $('Code — Métricas Semanais').item.json;
const rawResponse = $input.item.json;

let claudeText = '';
try {
  claudeText = rawResponse.content?.[0]?.text || rawResponse.text || '{}';
} catch (e) {
  claudeText = '{}';
}

let reportData;
try {
  const cleaned = claudeText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  reportData = JSON.parse(cleaned);
} catch (e) {
  reportData = {
    report_html: `<p>Caro/a ${deal.vendor_name},</p><p>Esta semana tivemos ${deal.metrics.visits_count} visita(s) e ${deal.metrics.inquiries_received} inquérito(s) para a sua propriedade em ${deal.address}. A actividade está ${deal.metrics.activity_trend}. Continuamos a trabalhar activamente na sua venda.</p><p>Qualquer questão, estou à disposição.</p>`,
    whatsapp_summary: `Relatório semanal: ${deal.metrics.visits_count} visita(s), ${deal.metrics.inquiries_received} inquérito(s) — ${deal.property_title.substring(0,40)}`,
    key_insight: `Fallback report. Activity: ${deal.metrics.activity_trend}, DOM: ${deal.metrics.days_on_market}d`
  };
}

// Build professional email HTML with AG branding
const emailHtml = `
<div style="font-family: Arial, sans-serif; max-width: 660px; margin: 0 auto; background: #ffffff;">
  <div style="background: #1c4a35; padding: 28px 36px; border-radius: 4px 4px 0 0;">
    <table style="width: 100%; border-collapse: collapse;">
      <tr>
        <td>
          <h1 style="color: #c9a96e; margin: 0; font-size: 20px; font-weight: 600; letter-spacing: 0.5px;">Agency Group</h1>
          <p style="color: rgba(255,255,255,0.6); margin: 4px 0 0 0; font-size: 12px; letter-spacing: 0.5px;">Relatório Semanal de Vendedor | AMI 22506</p>
        </td>
        <td style="text-align: right; vertical-align: top;">
          <p style="color: rgba(255,255,255,0.5); margin: 0; font-size: 11px;">${deal.week_of}</p>
        </td>
      </tr>
    </table>
  </div>
  <div style="background: #f8f6f0; padding: 16px 36px; border-left: 1px solid #eee; border-right: 1px solid #eee;">
    <p style="margin: 0; font-size: 13px; color: #666;">Propriedade</p>
    <p style="margin: 4px 0 0 0; font-size: 17px; font-weight: bold; color: #1c4a35;">${deal.property_title}</p>
    <p style="margin: 2px 0 0 0; font-size: 13px; color: #888;">${deal.address} &nbsp;|&nbsp; €${Number(deal.property_price).toLocaleString('pt-PT')} &nbsp;|&nbsp; ${deal.metrics.days_on_market} dias em mercado</p>
  </div>
  <div style="display: table; width: 100%; border-collapse: collapse; background: #fff; border: 1px solid #eee; border-top: none;">
    <div style="display: table-row;">
      <div style="display: table-cell; padding: 16px; text-align: center; border-right: 1px solid #f0f0f0;">
        <p style="margin: 0; font-size: 28px; font-weight: bold; color: #1c4a35;">${deal.metrics.visits_count}</p>
        <p style="margin: 4px 0 0 0; font-size: 12px; color: #888; text-transform: uppercase; letter-spacing: 0.5px;">Visitas</p>
      </div>
      <div style="display: table-cell; padding: 16px; text-align: center; border-right: 1px solid #f0f0f0;">
        <p style="margin: 0; font-size: 28px; font-weight: bold; color: #1c4a35;">${deal.metrics.inquiries_received}</p>
        <p style="margin: 4px 0 0 0; font-size: 12px; color: #888; text-transform: uppercase; letter-spacing: 0.5px;">Inquéritos</p>
      </div>
      <div style="display: table-cell; padding: 16px; text-align: center; border-right: 1px solid #f0f0f0;">
        <p style="margin: 0; font-size: 28px; font-weight: bold; color: #1c4a35;">${deal.metrics.avg_interest_level}/5</p>
        <p style="margin: 4px 0 0 0; font-size: 12px; color: #888; text-transform: uppercase; letter-spacing: 0.5px;">Interesse Médio</p>
      </div>
      <div style="display: table-cell; padding: 16px; text-align: center;">
        <p style="margin: 0; font-size: 18px; font-weight: bold; color: ${deal.metrics.price_position_pct > 10 ? '#c9a96e' : '#1c4a35'};">${deal.metrics.price_position_label}</p>
        <p style="margin: 4px 0 0 0; font-size: 12px; color: #888; text-transform: uppercase; letter-spacing: 0.5px;">Posição Preço</p>
      </div>
    </div>
  </div>
  <div style="padding: 32px 36px; background: #fff; border: 1px solid #eee; border-top: none; line-height: 1.7; color: #333; font-size: 14px;">
    ${reportData.report_html}
  </div>
  <div style="background: #1c4a35; padding: 16px 36px; border-radius: 0 0 4px 4px;">
    <p style="margin: 0; font-size: 11px; color: rgba(255,255,255,0.5);">Agency Group | AMI 22506 | Lisboa, Portugal | Relatório gerado automaticamente</p>
  </div>
</div>`;

return [{
  json: {
    ...deal,
    email_html: emailHtml,
    whatsapp_summary: reportData.whatsapp_summary,
    key_insight: reportData.key_insight,
    report_html_raw: reportData.report_html
  }
}];

// Aggregate all processed deals for final summary
const allItems = $input.all();
const dealsProcessed = allItems.map(i => ({
  deal_id: i.json.deal_id,
  vendor_name: i.json.vendor_name,
  property_title: i.json.property_title,
  days_on_market: i.json.metrics?.days_on_market,
  activity_trend: i.json.metrics?.activity_trend
}));

return [{
  json: {
    reports_sent: dealsProcessed.length,
    deals_processed: dealsProcessed,
    week_of: allItems[0]?.json.week_of || new Date().toLocaleDateString('pt-PT'),
    executed_at: new Date().toISOString()
  }
}];

